const feeds = ($env.WATCH_RSS_FEEDS || '').split(',').map(s => s.trim()).filter(Boolean);
if (!feeds.length) throw new Error('WATCH_RSS_FEEDS is empty');
const notionItems = $('Inbox IA — URLs existantes').all();
if (notionItems.some(i => i.json && i.json.error)) throw new Error('Unable to read existing Inbox URLs from Notion');
return feeds.map(feed_url => ({ json: { feed_url } }));

const MAX_ITEMS = Number($env.WATCH_MAX_ITEMS || 4);
const MAX_PER_HOST = Number($env.WATCH_MAX_PER_HOST || 2);
const MAX_AGE_HOURS = Number($env.WATCH_MAX_AGE_HOURS || 72);
const now = Date.now();

const textOf = (v) => {
  if (v == null) return '';
  if (Array.isArray(v)) return v.map(textOf).filter(Boolean).join(' ');
  if (typeof v === 'object') return v.plain_text || v.name || v.value || v.url || '';
  return String(v);
};
const normalizeUrl = (raw) => {
  let value = textOf(raw).trim().split('#')[0];
  if (!/^https?:\/\//i.test(value)) return '';
  value = value.replace(/([?&])(utm_[^=&]+|ref|source)=[^&]*/gi, '$1').replace(/[?&]+$/, '');
  return value.replace(/\/$/, '');
};
const hostOf = (url) => ((url.match(/^https?:\/\/([^/]+)/i) || [])[1] || '').replace(/^www\./, '');
const existing = new Set();
for (const item of $('Inbox IA — URLs existantes').all()) {
  const j = item.json || {}; const p = j.properties || {}; const src = { ...p, ...j };
  for (const key of ['property_url', 'URL', 'url']) { const value = normalizeUrl(textOf(src[key])); if (value) existing.add(value); }
}
const keywords = ($env.WATCH_KEYWORDS || '').split(',').map(s => s.trim().toLowerCase()).filter(Boolean);
if (!keywords.length) throw new Error('WATCH_KEYWORDS is empty');
const candidates = [];
for (const item of $input.all()) {
  const j = item.json || {};
  const url = normalizeUrl(j.link || j.guid || '');
  const title = textOf(j.title).trim();
  if (!url || !title || existing.has(url) || j.error) continue;
  const publishedRaw = j.isoDate || j.pubDate || j.published || j.updated;
  const publishedAt = publishedRaw ? new Date(publishedRaw).getTime() : NaN;
  if (!Number.isFinite(publishedAt) || publishedAt > now + 3600000 || now - publishedAt > MAX_AGE_HOURS * 3600000) continue;
  const excerpt = textOf(j.contentSnippet || j.content || j.summary || j.description).replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 1400);
  const haystack = (title + ' ' + excerpt).toLowerCase();
  let score = 0; const reasons = [];
  for (const term of keywords) {
    if (haystack.includes(term)) { score += term.includes(' ') ? 3 : 2; reasons.push(term); }
  }
  if (score < 2) continue;
  candidates.push({ url, title, excerpt, published_at: new Date(publishedAt).toISOString(), score, reasons: [...new Set(reasons)].slice(0, 4), host: hostOf(url) });
}
const counts = {}; const selected = [];
for (const c of candidates.sort((a, b) => b.score - a.score || new Date(b.published_at) - new Date(a.published_at))) {
  if ((counts[c.host] || 0) >= MAX_PER_HOST) continue;
  counts[c.host] = (counts[c.host] || 0) + 1; selected.push(c);
  if (selected.length >= MAX_ITEMS) break;
}
return selected.map(c => ({ json: c }));
